#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#define MAX_STR 305
#define MAX_LINE 5005

// Simple hash set using linear probing (enough for constraints)
typedef struct {
    char **data;
    int size;
    int capacity;
} HashSet;

unsigned int hash_func(const char *s, int cap) {
    unsigned int h = 0;
    while (*s) h = (h * 131) + (unsigned char)(*s++);
    return h % cap;
}

HashSet *create_set(int capacity) {
    HashSet *hs = (HashSet *)malloc(sizeof(HashSet));
    hs->capacity = capacity;
    hs->size = 0;
    hs->data = (char **)calloc(capacity, sizeof(char *));
    return hs;
}

void insert(HashSet *hs, const char *word) {
    int cap = hs->capacity;
    unsigned int idx = hash_func(word, cap);
    while (hs->data[idx]) {
        if (strcmp(hs->data[idx], word) == 0) return; // already present
        idx = (idx + 1) % cap;
    }
    hs->data[idx] = strdup(word);
    hs->size++;
}

int contains(HashSet *hs, const char *word) {
    int cap = hs->capacity;
    unsigned int idx = hash_func(word, cap);
    while (hs->data[idx]) {
        if (strcmp(hs->data[idx], word) == 0) return 1;
        idx = (idx + 1) % cap;
    }
    return 0;
}

void free_set(HashSet *hs) {
    for (int i = 0; i < hs->capacity; ++i) if (hs->data[i]) free(hs->data[i]);
    free(hs->data);
    free(hs);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    while (T--) {
        char inputString[MAX_STR];
        fgets(inputString, MAX_STR, stdin);
        inputString[strcspn(inputString, "\n")] = '\0';
        char dictLine[MAX_LINE];
        fgets(dictLine, MAX_LINE, stdin);
        dictLine[strcspn(dictLine, "\n")] = '\0';
        // build hash set
        HashSet *set = create_set(2048);
        char *token = strtok(dictLine, " ");
        while (token) {
            insert(set, token);
            token = strtok(NULL, " ");
        }
        int n = strlen(inputString);
        int dp[MAX_STR] = {0};
        dp[0] = 1;
        for (int i = 1; i <= n; ++i) {
            for (int j = 0; j < i; ++j) {
                if (!dp[j]) continue;
                // extract substring inputString[j..i-1]
                char sub[MAX_STR];
                int len = i - j;
                strncpy(sub, inputString + j, len);
                sub[len] = '\0';
                if (contains(set, sub)) {
                    dp[i] = 1;
                    break;
                }
            }
        }
        printf("%d\n", dp[n]);
        free_set(set);
    }
    return 0;
}

